fn test_vector_search_pipeline_with_simd() {
    // Setup: Create test index with known embeddings
    let temp_dir = tempfile::tempdir().unwrap();
    let index_path = temp_dir.path().join("test_index");

    // Create test documents with synthetic embeddings
    let docs = create_test_documents_with_embeddings(100);

    // Index documents
    let mut indexer = VectorIndexer::new(&index_path).unwrap();
    for doc in &docs {
        indexer.add_document(doc).unwrap();
    }
    indexer.commit().unwrap();

    // Search with a query embedding
    let query_embedding = create_query_embedding();
    let results = vector_search(&index_path, &query_embedding, 10).unwrap();

    // Verify results
    assert_eq!(results.len(), 10);

    // Verify ordering (scores should be descending)
    for i in 1..results.len() {
        assert!(results[i-1].score >= results[i].score,
            "Results not properly sorted: {} < {} at position {}",
            results[i-1].score, results[i].score, i);
    }

    // Verify known nearest neighbor is in top results
    let expected_nearest = find_nearest_neighbor_brute_force(&docs, &query_embedding);
    assert!(results.iter().any(|r| r.id == expected_nearest.id),
        "Expected nearest neighbor not in top 10 results");

    println!("✓ Vector search E2E test passed");
    println!("  - Indexed {} documents", docs.len());
    println!("  - Top result score: {}", results[0].score);
    println!("  - Query latency: logged separately");
}
